import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { useSensor } from '../hooks/useSensor';
import FingerprintAuth from '../components/auth/FingerprintAuth';
import LoginForm from '../components/auth/LoginForm';
import './AuthPages.css';

const LoginPage = () => {
    const navigate = useNavigate();
    const { login } = useAuth();
    const { status: sensorStatus } = useSensor();
    const [useFingerprint, setUseFingerprint] = useState(true);
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleFingerprintLogin = async (username) => {
        setLoading(true);
        setError('');
        
        const result = await login(username, null, true);
        
        if (result.success) {
            navigate('/dashboard');
        } else {
            setError(result.error);
        }
        
        setLoading(false);
    };

    const handlePasswordLogin = async (username, password) => {
        setLoading(true);
        setError('');
        
        const result = await login(username, password, false);
        
        if (result.success) {
            navigate('/dashboard');
        } else {
            setError(result.error);
        }
        
        setLoading(false);
    };

    return (
        <div className="auth-page">
            <div className="auth-container">
                <h1>Login</h1>
                
                {error && <div className="error-message">{error}</div>}
                
                {useFingerprint && sensorStatus.connected ? (
                    <FingerprintAuth 
                        onSuccess={handleFingerprintLogin}
                        loading={loading}
                    />
                ) : (
                    <LoginForm 
                        onSubmit={handlePasswordLogin}
                        loading={loading}
                    />
                )}
                
                <div className="auth-footer">
                    <button 
                        className="toggle-auth-method"
                        onClick={() => setUseFingerprint(!useFingerprint)}
                    >
                        {useFingerprint && sensorStatus.connected
                            ? 'Use password instead'
                            : 'Use fingerprint instead'}
                    </button>
                    
                    <p>
                        Don't have an account?{' '}
                        <a href="/register">Register here</a>
                    </p>
                </div>
            </div>
        </div>
    );
};

export default LoginPage;
